	"dataSources": {
		"ds_0v8FPPgk_ds_sRZag8F1_ds_i4wRou6J_ds_vy1Z66iY": {
			"name": "successful_actions_table",
			"options": {
				"query": "index=exoscale status<333 user IN ($user_tok$)\n| stats latest(_time) as latest_time c by user action command status\n| convert ctime(latest_time) as latest_time\n|  fields - c\n| head limit=10000 ($successful$=1)",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_1Fm6QhRP": {
			"name": "deleted_actions",
			"options": {
				"query": "index=exoscale sourcetype = exoscale:audittrail:mutation status<315 command=*delete* user IN ($user$) action IN ($action$)\n| stats c\n",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_1cYwYqbD": {
			"name": "line_4",
			"options": {
				"extend": "ds_m0nxWi6G",
				"query": "| append \n    [| makeresults format=csv data=\"action,Total\ndb2,0\ndb3,0\ndb4,0\ndb5,0\ndb6,0\" \n| table action Total]\n| head 6\n| eventstats sum(Total) as sum\n| eval perc = round((Total / sum) * 100)\n| table action perc\n| streamstats c\n\n\n\n| eval action = case(c==1, \"db1\", c==2, \"db2\", c==3, \"db3\", c==4, \"db4\", c==5, \"db5\", c==6, \"db6\", true(), action)\n| eval all = c . \" | \" . perc\n| eventstats values(all) as all\n| eval perc = mvindex(split(mvindex(all, 3), \" | \"), 1)\n| eval perc = case(c==1 AND perc>0, 100, c==2 AND perc>17, 100, c==3 AND perc>34, 100, c==4 AND perc>51, 100, c==5 AND perc>68, 100, c==6 AND perc>82, 100, true(), 0)\n| table action perc\n| head limit=100 ($most_performed_actions:job.resultCount$ > 3)"
			},
			"type": "ds.chain"
		},
		"ds_2Q2UC5sd": {
			"name": "users_drilldown",
			"options": {
				"extend": "ds_bdm7p81y",
				"query": "| eval successful_actions = if(status<400, command . \" - Action Performed Count (\" . c . \")\",  successful_actions), failed_actions = if(status>=400, command . \" - Action Performed Count (\" . c . \")\",  failed_actions)\n| stats values(action) as action values(successful_actions) as successful_actions values(failed_actions) as failed_actions by user\n| head limit=10000 ($usr$=1)"
			},
			"type": "ds.chain"
		},
