		"ds_VVWHhsek": {
			"name": "line_1",
			"options": {
				"extend": "ds_m0nxWi6G",
				"query": "| append \n    [| makeresults format=csv data=\"action,Total\ndb2,0\ndb3,0\ndb4,0\ndb5,0\ndb6,0\" \n| table action Total]\n| head 6\n| eventstats sum(Total) as sum\n| eval perc = round((Total / sum) * 100)\n| table action perc\n| streamstats c\n\n\n\n| eval action = case(c==1, \"db1\", c==2, \"db2\", c==3, \"db3\", c==4, \"db4\", c==5, \"db5\", c==6, \"db6\", true(), action)\n| eval all = c . \" | \" . perc\n| eventstats values(all) as all\n| eval perc = mvindex(split(mvindex(all, 0), \" | \"), 1)\n| eval perc = case(c==1 AND perc>0, 100, c==2 AND perc>17, 100, c==3 AND perc>34, 100, c==4 AND perc>51, 100, c==5 AND perc>68, 100, c==6 AND perc>=82, 100, true(), 0)\n| head limit=10000 ($most_performed_actions:job.resultCount$ > 0)"
			},
			"type": "ds.chain"
		},
		"ds_bdm7p81y": {
			"name": "main_search",
			"options": {
				"query": "index=exoscale user IN ($user$) action IN ($action$)\n| stats c by user action command status sourcetype _time",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_dRi1Znk0": {
			"name": "graph_search",
			"options": {
				"query": "index=exoscale user IN ($user$) action IN ($action$)\n\n\n| stats count by action user handler\n| sort - count\n|streamstats count as temp\n| eval text = mvsort(temp . \" | \" . user . \" | \" . handler . \" | \" . count)\n| stats values(text) as text by action\n| eval text=mvindex(text, 0, 9)\n| mvexpand text\n| eval new=split(text, \" | \"), command = mvindex(new, 2), user = mvindex(new, 1), count = mvindex(new, 3)\n| table user action command count\n| head limit=10000 ($graph$=1)",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_fraZP9Qb": {
			"name": "all_users",
